import type {
  ScaleLinear,
  ScaleLogarithmic,
  ScaleSymLog,
  ScaleTime,
} from 'd3-scale';

import type { TruncationMode } from '../../../../../typography/text-ellipsis/TextEllipsis.js';
import { useOverlay } from '../../overlay-tooltip/contexts/OverlayContext.js';
import { AnnotationsAtom } from '../AnnotationsAtom.js';
import { useAnnotationsSelectionState } from '../hooks/store/selectors.js';
import { useGroupedAnnotationsData } from '../hooks/useGroupedAnnotationsData.js';
import { useMarkerEventHandlers } from '../hooks/useMarkerEventHandlers.js';
import { MarkerAtom } from '../slots/MarkerAtom.js';
import { TrackAtom } from '../slots/TrackAtom.js';
import type { AnnotationsTrackConfig } from '../types/annotations-track-props.js';
import type { TextOverflowOptions } from '../types/marker.js';
import { calculateMarkerDimension } from '../utils/calculate-marker-dimension.js';
import { defineMarkerBrightnessState } from '../utils/define-marker-brightness-state.js';
import { defineMarkerColor } from '../utils/define-marker-color.js';
import { defineMarkerContent } from '../utils/define-marker-content.js';

type AnnotationsRendererProps = {
  scale:
    | ScaleTime<number, number>
    | ScaleLinear<number, number>
    | ScaleLogarithmic<number, number>
    | ScaleSymLog<number, number>;
  width: number;
  labelsOffset: number;
  showLabels: boolean;
  tracks: AnnotationsTrackConfig[];
  textOverflow: TextOverflowOptions;
  truncateMode?: TruncationMode;
};

export const AnnotationsRenderer = (props: AnnotationsRendererProps) => {
  const {
    scale,
    width,
    labelsOffset,
    showLabels,
    tracks,
    textOverflow,
    truncateMode,
  } = props;
  const overlay = useOverlay();
  const groupedData = useGroupedAnnotationsData(tracks, scale.domain());

  const selection = useAnnotationsSelectionState();
  const { handleMouseEnter, handleMouseMove, handleMouseLeave, handleClick } =
    useMarkerEventHandlers(overlay.overlayRef);

  return (
    <AnnotationsAtom
      width={width}
      labelsWidth={labelsOffset}
      showLabels={showLabels}
    >
      {groupedData.map((track, trackNumber) => {
        const currentTrack = Array.from(track.markers.entries());

        return (
          <TrackAtom
            label={track.label}
            hidden={track.hidden}
            key={trackNumber}
          >
            {currentTrack.map(([groupId, annotationsGroup]) => {
              return [...annotationsGroup] // this is needed because sort method mutates the original array, and affects the order of the tooltip items
                .sort((a, b) => a.priority - b.priority)
                .map(({ key: markerId, markers }) => {
                  const [marker] = markers;

                  const color = defineMarkerColor(markers);

                  const state = defineMarkerBrightnessState(
                    markerId,
                    selection,
                  );

                  const { x, width } = calculateMarkerDimension(marker, scale);

                  const markerContent = defineMarkerContent(markers);

                  return (
                    <MarkerAtom
                      key={markerId}
                      x={x}
                      width={width}
                      color={color}
                      onMouseEnter={handleMouseEnter(
                        markerId,
                        groupId,
                        annotationsGroup,
                      )}
                      onMouseMove={handleMouseMove}
                      onMouseLeave={handleMouseLeave}
                      onClick={handleClick(groupId, annotationsGroup)}
                      content={markerContent}
                      interactionState={state}
                      textOverflow={textOverflow}
                      truncateMode={truncateMode}
                    />
                  );
                });
            })}
          </TrackAtom>
        );
      })}
    </AnnotationsAtom>
  );
};

(
  AnnotationsRenderer as typeof AnnotationsRenderer & {
    displayName: string;
  }
).displayName = 'AnnotationsContent';
